t['\u5982\u679c\u5bf9\u4f60\u6709\u5e2e\u52a9\uff0c\u8bb0\u5f97\u5173\u6ce8\u4e00\u6ce2~ '] = 'N\u1ebfu th\u1ea5y h\u1eefu \u00edch, nh\u1edb theo d\u00f5i nh\u00e9~ '
t['\u98de\u4e66\u63d2\u4ef6'] = 'Plugin Feishu'
