t['5\u3001Multi Search Engine\uff1a '] = '5. Multi Search Engine: '
t['\u805a\u5408\u641c\u7d22\uff0c\u540c\u65f6\u641c\u591a\u4e2a\u5f15\u64ce\uff0c\u9002\u5408\u6df1\u5ea6\u7814\u7a76\u548c\u51b7\u95e8\u8d44\u6599\u3002'] = 'T\u00ecm ki\u1ebfm t\u1ed5ng h\u1ee3p, t\u00ecm \u0111\u1ed3ng th\u1eddi nhi\u1ec1u c\u00f4ng c\u1ee5, ph\u00f9 h\u1ee3p nghi\u00ean c\u1ee9u chuy\u00ean s\u00e2u v\u00e0 t\u00e0i li\u1ec7u \u00edt ph\u1ed5 bi\u1ebfn.'
t['6\u3001CSV Data Analyzer\uff1a '] = '6. CSV Data Analyzer: '
