t['7\u3001Office-Automation\uff1a '] = '7. Office-Automation: '
t['\u529e\u516c\u81ea\u52a8\u5316\uff0c\u6279\u91cf\u5904\u7406 Office/PDF\uff0c\u9002\u5408\u5408\u540c\u62a5\u8868\u6587\u4ef6\u3002'] = 'T\u1ef1 \u0111\u1ed9ng h\u00f3a v\u0103n ph\u00f2ng, x\u1eed l\u00fd h\u00e0ng lo\u1ea1t Office/PDF, ph\u00f9 h\u1ee3p h\u1ee3p \u0111\u1ed3ng b\u00e1o c\u00e1o t\u00e0i li\u1ec7u.'
t['8\u3001Tavily Search\uff1a '] = '8. Tavily Search: '
t['\u4e13\u4e1a AI \u641c\u7d22\uff0c\u7ed3\u679c\u66f4\u7ed3\u6784\u5316\uff0c\u9002\u5408\u7814\u7a76\u3001\u6838\u67e5\u3001\u65b0\u95fb\u3002'] = 'T\u00ecm ki\u1ebfm AI chuy\u00ean nghi\u1ec7p, k\u1ebft qu\u1ea3 c\u00f3 c\u1ea5u tr\u00fac h\u01a1n, ph\u00f9 h\u1ee3p nghi\u00ean c\u1ee9u, ki\u1ec3m ch\u1ee9ng, tin t\u1ee9c.'
t['9\u3001File Manager\uff1a '] = '9. File Manager: '
t['\u6587\u4ef6\u7ba1\u7406\uff0c\u6574\u7406\u5f52\u6863\u6e05\u7406\u91cd\u547d\u540d\uff0c\u9002\u5408\u7ba1\u6587\u4ef6\u548c\u6e05\u786c\u76d8\u3002'] = 'Qu\u1ea3n l\u00fd file, s\u1eafp x\u1ebfp l\u01b0u tr\u1eef d\u1ecdn d\u1eb9p \u0111\u1ed5i t\u00ean, ph\u00f9 h\u1ee3p qu\u1ea3n l\u00fd file v\u00e0 d\u1ecdn \u1ed5 c\u1ee9ng.'
t['10\u3001Email Assistant\uff1a '] = '10. Email Assistant: '
t['\u90ae\u4ef6\u52a9\u624b\uff0c\u5206\u7c7b\u6458\u8981\u56de\u590d\u63d0\u9192\uff0c\u9002\u5408\u9ad8\u9891\u90ae\u4ef6\u5904\u7406\u3002'] = 'Tr\u1ee3 l\u00fd email, ph\u00e2n lo\u1ea1i t\u00f3m t\u1eaft tr\u1ea3 l\u1eddi nh\u1eafc nh\u1edf, ph\u00f9 h\u1ee3p x\u1eed l\u00fd email t\u1ea7n su\u1ea5t cao.'
t['11\u3001Data Analysis\uff1a '] = '11. Data Analysis: '
t['\u5168\u6808\u5206\u6790\uff0c\u591a\u6570\u636e\u6e90\u51fa\u62a5\u544a\u770b\u677f\uff0c\u9002\u5408\u4e1a\u52a1\u6c47\u62a5\u3002'] = 'Ph\u00e2n t\u00edch full-stack, nhi\u1ec1u ngu\u1ed3n d\u1eef li\u1ec7u xu\u1ea5t b\u00e1o c\u00e1o dashboard, ph\u00f9 h\u1ee3p b\u00e1o c\u00e1o kinh doanh.'
t['12\u3001SEO\uff1a '] = '12. SEO: '
