t['13\u3001Writing Assistant\uff1a '] = '13. Writing Assistant: '
t['\u5199\u4f5c\u52a9\u624b\uff0c\u5199\u7a3f\u6da6\u8272\u6539\u98ce\u683c\uff0c\u9002\u5408\u6587\u6848\u62a5\u544a\u90ae\u4ef6\u3002'] = 'Tr\u1ee3 l\u00fd vi\u1ebft, so\u1ea1n b\u00e0i ch\u1ec9nh s\u1eeda thay \u0111\u1ed5i phong c\u00e1ch, ph\u00f9 h\u1ee3p copywriting b\u00e1o c\u00e1o email.'
t['14\u3001Humanizer\uff1a '] = '14. Humanizer: '
t['\u5185\u5bb9\u4eba\u6027\u5316\uff0c\u628a AI \u6587\u6848\u6539\u5f97\u66f4\u50cf\u4eba\u5199\u3002'] = 'Nh\u00e2n h\u00f3a n\u1ed9i dung, bi\u1ebfn b\u00e0i vi\u1ebft AI th\u00e0nh gi\u1ed1ng ng\u01b0\u1eddi vi\u1ebft h\u01a1n.'
t['\u590d\u5236\u4ee5\u4e0b\u4fe1\u606f\uff0c\u4e00\u952e\u5b89\u88c5'] = 'Sao ch\u00e9p th\u00f4ng tin d\u01b0\u1edbi \u0111\u00e2y, c\u00e0i \u0111\u1eb7t m\u1ed9t ch\u1ea1m'
t['\u82e5\u9047\u5230\u9650\u6d41\u60c5\u51b5\uff0c\u8ddf\u4ed6\u8bf4 '] = 'N\u1ebfu g\u1eb7p t\u00ecnh tr\u1ea1ng gi\u1edbi h\u1ea1n t\u1ed1c \u0111\u1ed9, n\u00f3i v\u1edbi n\u00f3 '
t['\u81ea\u5df1\u5b9a\u65f6\u83b7\u53d6\uff0c\u6216\u8005\u76f4\u63a5\u4e0b\u8f7d\u5230\u672c\u5730\u8fdb\u884c\u5b89\u88c5'] = 't\u1ef1 l\u00ean l\u1ecbch l\u1ea5y, ho\u1eb7c t\u1ea3i tr\u1ef1c ti\u1ebfp v\u1ec1 m\u00e1y \u0111\u1ec3 c\u00e0i \u0111\u1eb7t'
t['\u7aef\u4e91\u534f\u540c\u662f\u600e\u4e48\u56de\u4e8b\uff1f'] = 'Ph\u1ed1i h\u1ee3p c\u1ee5c b\u1ed9 - \u0111\u00e1m m\u00e2y l\u00e0 g\u00ec?'
t['ArkClaw \u6700\u6709\u610f\u601d\u7684\u5730\u65b9\uff0c\u662f\u5b83\u652f\u6301\u7aef\u4e91\u534f\u540c\u3002'] = '\u0110i\u1ec1u th\u00fa v\u1ecb nh\u1ea5t c\u1ee7a ArkClaw l\u00e0 n\u00f3 h\u1ed7 tr\u1ee3 ph\u1ed1i h\u1ee3p c\u1ee5c b\u1ed9 - \u0111\u00e1m m\u00e2y.'
t['\u4ec0\u4e48\u610f\u601d\uff1f'] = 'Ngh\u0129a l\u00e0 g\u00ec?'
t['\u5c31\u662f\u4f60\u5728\u672c\u5730\u5f00\u53d1\uff0cArkClaw \u5728\u4e91\u7aef\u6267\u884c\uff0c\u4e24\u8fb9\u6570\u636e\u5b9e\u65f6\u540c\u6b65\u3002'] = 'T\u1ee9c l\u00e0 b\u1ea1n ph\u00e1t tri\u1ec3n \u1edf m\u00e1y c\u1ee5c b\u1ed9, ArkClaw th\u1ef1c thi tr\u00ean \u0111\u00e1m m\u00e2y, d\u1eef li\u1ec7u hai b\u00ean \u0111\u1ed3ng b\u1ed9 th\u1eddi gian th\u1ef1c.'
