t['\u8bc4\u8bba\u533a\u804a\u804a\uff0c\u8001\u91d1\u6211\u5f88\u597d\u5947\u4f60\u4eec\u5728\u7528\u5c0f\u9f99\u867e\u641e\u4ec0\u4e48\u3002'] = 'B\u00ecnh lu\u1eadn b\u00ean d\u01b0\u1edbi nh\u00e9, L\u00e3o Kim t\u00f4i r\u1ea5t t\u00f2 m\u00f2 c\u00e1c b\u1ea1n \u0111ang d\u00f9ng t\u00f4m h\u00f9m nh\u1ecf l\u00e0m g\u00ec.'
t['\u4f53\u9a8c\u5730\u5740\uff1a '] = '\u0110\u1ecba ch\u1ec9 tr\u1ea3i nghi\u1ec7m: '

# Apply translations
trans_data = copy.deepcopy(data)
translated_count = 0
kept_count = 0
total_text_runs = 0
untranslated = []

for block in trans_data['blocks']:
    for el in block['elements']:
        if el['type'] == 'text_run':
            total_text_runs += 1
            content = el['content']
            if content in t:
                el['content'] = t[content]
                if t[content] != content:
                    translated_count += 1
                else:
                    kept_count += 1
            elif not has_chinese(content):
                kept_count += 1
            else:
                untranslated.append(content)

# Add space between adjacent Vietnamese text_runs where needed
for block in trans_data['blocks']:
    elements = block['elements']
    for i in range(len(elements) - 1):
        el = elements[i]
        next_el = elements[i + 1]
        if el['type'] == 'text_run' and next_el['type'] == 'text_run':
            curr = el['content']
            nxt = next_el['content']
            if curr and nxt:
                last_char = curr[-1]
                first_char = nxt[0]
                # Add space if both are alphanumeric/Vietnamese and no space exists
                if (not last_char.isspace() and
                    not first_char.isspace() and
                    last_char not in '.,!?;:)]}\'"' and
                    first_char not in '.,!?;:)]}\'"'):
                    # Check if it's Vietnamese text running together
                    if (ord(last_char) > 127 or last_char.isalpha()) and (ord(first_char) > 127 or first_char.isalpha()):
                        el['content'] = curr + ' '

print(f'Total text_runs: {total_text_runs}')
print(f'Translated: {translated_count}')
print(f'Kept as-is: {kept_count}')
print(f'Untranslated: {len(untranslated)}')
for u in untranslated:
    print(f'  MISS: {repr(u)}')

with open('_art_b7_3_trans.json', 'w', encoding='utf-8') as f:
    json.dump(trans_data, f, ensure_ascii=False, indent=2)
print('Saved to _art_b7_3_trans.json')
